import react, { useState, useMemo } from 'react';

const records = [
    { id: 1, name: 'adam', age: 25 },
    { id: 2, name: 'james', age: 30 },
    { id: 3, name: 'nick', age: 28 },
    { id: 4, name: 'john', age: 29 }
];

const sortabletable = () => {
    const [sortconfig, setsortconfig] = useState({ key: null, direction: 'asc' });
    const [filtertext, setfiltertext] = useState('');

    const handleclick = (key) => {
        let direction = 'asc';
        if (sortconfig.key === key && sortconfig.direction === 'asc') {
            direction = 'desc';
        }
        setsortconfig({ key, direction });
    };

    const handlefilterchange = (e) => {
        setfiltertext(e.target.value);
    };

    const processeddata = useMemo(() => {
        let result = [...records];

        if (filtertext) {
            result = result.filter(record =>
                record.name.toLowerCase().includes(filtertext.toLowerCase())
            );
        }

        if (sortconfig.key) {
            result.sort((a, b) => {
                if (a[sortconfig.key] < b[sortconfig.key]) {
                    return sortconfig.direction === 'asc' ? -1 : 1;
                }
                if (a[sortconfig.key] > b[sortconfig.key]) {
                    return sortconfig.direction === 'asc' ? 1 : -1;
                }
                return 0;
            });
        }

        return result;
    }, [records, sortconfig, filtertext]);

    return (
        <div>
            <input
                type="text"
                placeholder="filter by name"
                value={filtertext}
                onchange={handlefilterchange}
            />
            <table border="1">
                <thead>
                    <tr>
                        <th onclick={() => handleclick('id')}>id {sortconfig.key === 'id' ? (sortconfig.direction === 'asc' ? '↑' : '↓') : ''}</th>
